fixed_code:
// Option 1: let elision rules infer it (cleanest for simple cases)
fn first_word_elided(s: &str) -> &str {
    s.split_whitespace().next().unwrap_or("")
}

// Option 2: explicit '_ in both positions (shows the relationship clearly)
fn first_word_explicit(s: &'_ str) -> &'_ str {
    s.split_whitespace().next().unwrap_or("")
}

// Option 3: named lifetime (most explicit, best for documentation)
fn first_word_named<'a>(s: &'a str) -> &'a str {
    s.split_whitespace().next().unwrap_or("")
}

// When '_ is most useful: disambiguating complex types in return position
use std::collections::HashMap;
fn get_keys(map: &HashMap<String, i32>) -> impl Iterator<Item = &'_ str> {
    map.keys().map(|s| s.as_str())
}

fn main() {
    let s = String::from("hello world");
    println!("{}", first_word_elided(&s));
    println!("{}", first_word_explicit(&s));
    let map = HashMap::from([(String::from("x"), 1)]);
    println!("{:?}", get_keys(&map).collect::<Vec<_>>());
}

