fixed_code:
use std::fmt::Display;

// Option A: 'static bound — the boxed value can be stored anywhere, outlives any borrow
struct Wrapper {
    value: Box<dyn Display + 'static>,  // explicit 'static
}

impl Wrapper {
    fn new(v: impl Display + 'static) -> Self {
        Wrapper { value: Box::new(v) }
    }
    fn show(&self) { println!("{}", self.value); }
}

// Option B: struct with lifetime — allows boxing borrowed values
struct BorrowedWrapper<'a> {
    value: Box<dyn Display + 'a>,  // can hold values that borrow for 'a
}

impl<'a> BorrowedWrapper<'a> {
    fn new(v: impl Display + 'a) -> Self {
        BorrowedWrapper { value: Box::new(v) }
    }
    fn show(&self) { println!("{}", self.value); }
}

fn main() {
    // Option A: works with owned values
    let w = Wrapper::new(String::from("hello"));
    w.show();

    // Option B: can hold references too
    let s = String::from("world");
    let bw = BorrowedWrapper::new(s.as_str());
    bw.show();
}

