fixed_code:
use std::collections::HashMap;

// Add lifetime for prefix too, and constrain the returned iterator
// to the shorter of the two lifetimes
fn matching_keys<'a, 'p>(
    map: &'a HashMap<String, i32>,
    prefix: &'p str,
) -> impl Iterator<Item = &'a str> + 'p  // iterator borrows prefix for 'p
where
    'a: 'p,  // map data must outlive prefix (or use min lifetime)
{
    map.keys()
        .filter(move |k| k.starts_with(prefix))  // move captures prefix
        .map(|k| k.as_str())
}

fn main() {
    let map = HashMap::from([
        (String::from("apple"), 1),
        (String::from("banana"), 2),
        (String::from("apricot"), 3),
    ]);
    let prefix = String::from("ap");
    let matches: Vec<&str> = matching_keys(&map, &prefix).collect();
    println!("{:?}", matches);
}

