// What does '_ mean in each position below?
fn confusing<'a>(input: &'a str) -> Guard<'_> {  // 1: what lifetime is '_?
    Guard(input)
}

fn also_confusing(input: &str) -> Guard<'_> {  // 2: what lifetime is '_?
    Guard(input)
}

// Does '_ in let bindings work?
fn binding_test(input: &str) {
    let g: Guard<'_> = Guard(input);  // 3: what does this mean?
    println!("{}", g.0);
